// client/hooks/useThrottle.ts
import { useEffect, useRef, useState } from 'react';
export function useThrottle<T>(value: T, delay: number): T {
  const [throttled, setThrottled] = useState(value);
  const lastUpdateRef = useRef(Date.now());
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    const elapsed = Date.now() - lastUpdateRef.current;
    if (elapsed >= delay) { setThrottled(value); lastUpdateRef.current = Date.now(); }
    else {
      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = window.setTimeout(() => { setThrottled(value); lastUpdateRef.current = Date.now(); }, delay - elapsed);
    }
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [value, delay]);
  return throttled;
}

// client/hooks/useFocusTrap.ts
import { useEffect, useRef, RefObject } from 'react';
export function useFocusTrap(ref: RefObject<HTMLElement>, enabled: boolean) {
  const previousFocusRef = useRef<HTMLElement | null>(null);
  useEffect(() => {
    if (!enabled || !ref.current) return;
    previousFocusRef.current = document.activeElement as HTMLElement;
    const focusables = ref.current.querySelectorAll<HTMLElement>('a[href], button:not([disabled]), input:not([disabled]), select, textarea, [tabindex]:not([tabindex="-1"])');
    const first = focusables[0]; const last = focusables[focusables.length - 1];
    first?.focus();
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last?.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first?.focus(); }
    };
    document.addEventListener('keydown', onKey);
    return () => { document.removeEventListener('keydown', onKey); previousFocusRef.current?.focus(); };
  }, [enabled]);
}

// client/hooks/useTimeout.ts
import { useCallback, useEffect, useRef } from 'react';
export function useTimeout(callback: () => void, delay: number | null) {
  const cbRef = useRef(callback);
  const timerRef = useRef<number | null>(null);
  useEffect(() => { cbRef.current = callback; }, [callback]);
  const cancel = useCallback(() => { if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; } }, []);
  const reset = useCallback(() => { cancel(); if (delay !== null) timerRef.current = window.setTimeout(() => cbRef.current(), delay); }, [delay, cancel]);
  useEffect(() => { reset(); return cancel; }, [reset, cancel]);
  return { cancel, reset };
}

