// server/routes/health.ts
import { Router } from 'express';
import mongoose from 'mongoose';
import { redis } from '../redis';
export const healthRouter = Router();
healthRouter.get('/healthz', (_req, res) => res.status(200).send('ok'));
healthRouter.get('/readyz', async (_req, res) => {
  const checks = await Promise.allSettled([
    mongoose.connection.readyState === 1 ? Promise.resolve() : Promise.reject('mongo'),
    redis.ping()
  ]);
  const failed = checks.filter(c => c.status === 'rejected');
  if (failed.length) return res.status(503).json({ status: 'unhealthy', failed: failed.map(f => (f as any).reason) });
  res.json({ status: 'ready' });
});

