import { z } from 'zod';
export function PaginatedSchema<T extends z.ZodTypeAny>(item: T) {
  return z.discriminatedUnion('kind', [
    z.object({ kind: z.literal('empty') }),
    z.object({ kind: z.literal('page'), items: z.array(item), nextCursor: z.string() }),
    z.object({ kind: z.literal('last'), items: z.array(item) })
  ]);
}

