// server/jobs/scheduleEvaluator.ts
import cronParser from 'cron-parser';
export async function evaluateSchedules() {
  const now = new Date();
  const schedules = await ScheduleModel.find({ enabled: true });
  for (const s of schedules) {
    const interval = cronParser.parseExpression(s.cron, { tz: s.timezone, currentDate: new Date(now.getTime() - 60000) });
    const next = interval.next().toDate();
    if (Math.abs(next.getTime() - now.getTime()) < 60000) {
      await enqueue('tenant.report', { tenantId: s.tenantId });
    }
  }
}

// server/jobs/trialReminders.ts
export async function trialReminders() {
  const trials = await SubscriptionModel.find({ status: 'trialing' });
  for (const t of trials) {
    const daysLeft = Math.ceil((t.trialEndsAt.getTime() - Date.now()) / 86400000);
    if ([7, 2, 1].includes(daysLeft) && !t.reminderSent.includes(daysLeft)) {
      await emailJob.send({ to: t.contactEmail, template: `trial_reminder_${daysLeft}d`, data: { daysLeft } });
      t.reminderSent.push(daysLeft);
      await t.save();
    }
  }
}

// server/services/shareService.ts
import crypto from 'crypto';
export const shareService = {
  async create(resourceId: string, permission: 'view' | 'comment', expiresAt: Date) {
    const token = crypto.randomBytes(24).toString('base64url');
    await ShareModel.create({ token, resourceId, permission, expiresAt, createdBy: currentUser() });
    return token;
  },
  async resolve(token: string) {
    const s = await ShareModel.findOne({ token });
    if (!s || s.expiresAt < new Date() || s.revoked) throw new NotFoundError();
    return s;
  }
};

