export const refundService = {
  async refund(invoiceId: string, amountCents: number, reason: string) {
    const invoice = await stripe.invoices.retrieve(invoiceId);
    if (!invoice.payment_intent) throw new ConflictError('Not paid');
    const refund = await stripe.refunds.create({ payment_intent: invoice.payment_intent as string, amount: amountCents, reason: 'requested_by_customer', metadata: { reason } });
    await audit('billing:refund', { subjectId: invoice.customer as string, after: { refundId: refund.id, amount: amountCents, reason } });
    return refund;
  }
};

// server/middleware/ipAllowlist.ts
import { RequestHandler } from 'express';
import ipaddr from 'ipaddr.js';
import { ForbiddenError } from '../errors';
export const ipAllowlistMiddleware: RequestHandler = async (req, _res, next) => {
  const tenant = (req as any).user?.tenantId;
  if (!tenant) return next();
  const allowlist = await ipAllowlistDal.getForTenant(tenant);
  if (!allowlist.length) return next();
  const realIp = req.ip;
  if (!realIp) return next(new ForbiddenError('IP unknown'));
  const addr = ipaddr.process(realIp);
  const allowed = allowlist.some(cidr => {
    const [range, prefix] = ipaddr.parseCIDR(cidr);
    return addr.kind() === range.kind() && (addr as any).match([range, prefix]);
  });
  if (!allowed) return next(new ForbiddenError('IP not allowed'));
  next();
};

