import { Mercator, Graticule } from '@visx/geo';
import { useMemo } from 'react';
import * as topojson from 'topojson-client';
export function WorldMap({ topology, width, height }: { topology: any; width: number; height: number }) {
  const features = useMemo(() => topojson.feature(topology, topology.objects.countries) as any, [topology]);
  return (
    <svg width={width} height={height}>
      <Mercator data={features.features} scale={150} center={[0, 30]}>
        {projection => <g>{projection.features.map(({ feature, path }, i) => <path key={i} d={path ?? ''} fill="#e5e7eb" stroke="#9ca3af" />)}</g>}
      </Mercator>
    </svg>
  );
}

